9-the-fs-promises-api.golden_snippet:
import { writeFile } from 'fs/promises';

export class CollaborativeDocument {
  constructor() {
    this.content = '';
    this.clients = new Set();
  }

  addClient(id) {
    this.clients.add(id);
  }

  removeClient(id) {
    this.clients.delete(id);
  }

  async save(filename) {
    await writeFile(filename, this.content, 'utf8');
    return true;
  }
}

